using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Notes storage shared across tool invocations ---
var notes = new List<string>();

// --- Define the tools the agent can use ---
var searchTool = AIFunctionFactory.Create(
    ([Description("The search query to look up on the web")] string query) =>
    {
        Console.WriteLine($"  🔍 Searching the web for: \"{query}\"");

        // Simulated search results keyed by topic keywords
        var results = new Dictionary<string, string[]>(StringComparer.OrdinalIgnoreCase)
        {
            ["quantum computing"] =
            [
                "Quantum computers use qubits that can exist in superposition, enabling parallel computation. Google's Willow chip (2024) achieved 105 qubits with exponential error-correction improvements.",
                "IBM unveiled its Heron processor and plans a 100,000-qubit system by 2033. Current applications include cryptography research, drug discovery simulations, and optimization problems.",
                "Microsoft announced its Majorana-1 chip using topological qubits for better stability. Quantum advantage has been demonstrated for specific sampling tasks but general-purpose use remains years away."
            ],
            ["artificial intelligence"] =
            [
                "Large language models like GPT-5 and Claude have pushed AI capabilities in reasoning, coding, and multimodal understanding. The transformer architecture remains dominant.",
                "AI agents that can use tools, browse the web, and write code are a major 2025 trend. Frameworks like LangChain, Semantic Kernel, and Microsoft.Extensions.AI simplify agent development.",
                "Concerns around AI safety, alignment, and regulation continue to grow. The EU AI Act is being enforced, and the US has issued executive orders on AI safety standards."
            ],
            ["climate change"] =
            [
                "Global temperatures in 2025 are tracking 1.3°C above pre-industrial levels. The Paris Agreement goal of limiting warming to 1.5°C is increasingly difficult to meet.",
                "Renewable energy capacity surpassed fossil fuels for new installations in 2024. Solar panel costs dropped 20% year-over-year, making solar the cheapest energy source in most regions.",
                "Carbon capture technology is scaling up with several gigaton-scale projects announced. However, experts emphasize that emissions reduction must remain the primary strategy."
            ]
        };

        // Find best matching results
        foreach (var (key, value) in results)
        {
            if (query.Contains(key, StringComparison.OrdinalIgnoreCase))
                return string.Join("\n\n", value.Select((r, i) => $"Result {i + 1}: {r}"));
        }

        return $"Result 1: {query} is an active area of research with many recent developments. "
             + "Key themes include technological breakthroughs, policy implications, and future outlook. "
             + "More specific queries may yield better results.";
    },
    new AIFunctionFactoryOptions
    {
        Name = "search_web",
        Description = "Search the web for current information on a topic. Returns relevant search result snippets."
    });

var addNoteTool = AIFunctionFactory.Create(
    ([Description("The note content to save")] string note) =>
    {
        notes.Add(note);
        Console.WriteLine($"  📝 Note saved ({notes.Count} total)");
        return $"Note saved successfully. You now have {notes.Count} note(s).";
    },
    new AIFunctionFactoryOptions
    {
        Name = "add_note",
        Description = "Save a research note for later reference. Use this to record key findings from search results."
    });

var getNotesTool = AIFunctionFactory.Create(
    () =>
    {
        if (notes.Count == 0)
            return "No notes saved yet.";
        return string.Join("\n", notes.Select((n, i) => $"[{i + 1}] {n}"));
    },
    new AIFunctionFactoryOptions
    {
        Name = "get_notes",
        Description = "Retrieve all saved research notes to review findings before writing a summary."
    });

// --- Build the chat client with tool support ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "no-key";
var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(modelName).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools = [searchTool, addNoteTool, getNotesTool]
};

// --- Pick a research topic ---
Console.Write("Enter a research topic (or press Enter for 'quantum computing'): ");
var topic = Console.ReadLine();
if (string.IsNullOrWhiteSpace(topic))
    topic = "quantum computing";

Console.WriteLine($"\n🤖 Research Agent Starting — Topic: \"{topic}\"\n");

var systemPrompt = """
    You are a research agent. Your job is to research a given topic thoroughly and produce a summary.

    Follow this workflow:
    1. Search the web 2-3 times with different queries to gather diverse information.
    2. After each search, save the key findings as notes using the add_note tool.
    3. Once you have enough information, retrieve your notes with get_notes.
    4. Write a well-structured summary with sections: Overview, Key Developments, and Outlook.

    Be thorough but concise. Cite specific facts and figures from your research.
    """;

var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User, $"Please research the following topic and provide a comprehensive summary: {topic}")
};

// --- Run the agent ---
var response = await client.GetChatResponseAsync(messages, chatOptions);

Console.WriteLine("\n══════════════════════════════════════════");
Console.WriteLine("  📋  RESEARCH SUMMARY");
Console.WriteLine("══════════════════════════════════════════\n");
Console.WriteLine(response.Text);
Console.WriteLine();

